#include <string>
std::string run_length_encode(const std::string& s) {
    if (s.empty()) return "";
    std::string result;
    int count = 1;
    for (int i = 1; i <= (int)s.size(); i++) {
        if (i < (int)s.size() && s[i] == s[i-1]) {
            count++;
        } else {
            result += std::to_string(count) + s[i-1];
            count = 1;
        }
    }
    return result;
}

